/// Compute squared L2 distance between two 128-dim f32 vectors.
/// Returns the squared Euclidean distance as f64.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    l2_distance_f32(a, b) as f64
}

/// Squared L2 distance returning f32 accumulator (for speed).
#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        }
        if is_x86_feature_detected!("avx2") {
            return unsafe { l2_distance_avx2(a, b) };
        }
    }
    l2_distance_scalar(a, b)
}

#[inline(always)]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for i in 0..a.len() {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
#[inline]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;
    let n = a.len();
    let mut acc0 = _mm256_setzero_ps();
    let mut acc1 = _mm256_setzero_ps();
    let mut acc2 = _mm256_setzero_ps();
    let mut acc3 = _mm256_setzero_ps();

    let chunks = n / 32;
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    for i in 0..chunks {
        let offset = i * 32;
        let a0 = _mm256_loadu_ps(a_ptr.add(offset));
        let b0 = _mm256_loadu_ps(b_ptr.add(offset));
        let d0 = _mm256_sub_ps(a0, b0);
        acc0 = _mm256_fmadd_ps(d0, d0, acc0);

        let a1 = _mm256_loadu_ps(a_ptr.add(offset + 8));
        let b1 = _mm256_loadu_ps(b_ptr.add(offset + 8));
        let d1 = _mm256_sub_ps(a1, b1);
        acc1 = _mm256_fmadd_ps(d1, d1, acc1);

        let a2 = _mm256_loadu_ps(a_ptr.add(offset + 16));
        let b2 = _mm256_loadu_ps(b_ptr.add(offset + 16));
        let d2 = _mm256_sub_ps(a2, b2);
        acc2 = _mm256_fmadd_ps(d2, d2, acc2);

        let a3 = _mm256_loadu_ps(a_ptr.add(offset + 24));
        let b3 = _mm256_loadu_ps(b_ptr.add(offset + 24));
        let d3 = _mm256_sub_ps(a3, b3);
        acc3 = _mm256_fmadd_ps(d3, d3, acc3);
    }

    acc0 = _mm256_add_ps(acc0, acc2);
    acc1 = _mm256_add_ps(acc1, acc3);
    acc0 = _mm256_add_ps(acc0, acc1);

    // Handle remainder
    let mut sum = hsum_avx2(acc0);
    let remainder_start = chunks * 32;
    for i in remainder_start..n {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
#[inline]
unsafe fn hsum_avx2(v: std::arch::x86_64::__m256) -> f32 {
    use std::arch::x86_64::*;
    let lo = _mm256_castps256_ps128(v);
    let hi = _mm256_extractf128_ps(v, 1);
    let sum128 = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(sum128);
    let sum64 = _mm_add_ps(sum128, shuf);
    let shuf2 = _mm_movehl_ps(shuf, sum64);
    let sum32 = _mm_add_ss(sum64, shuf2);
    _mm_cvtss_f32(sum32)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;
    let n = a.len();
    // 128 floats = 4 x 16-float zmm registers, unrolled 4x
    let mut acc0 = _mm512_setzero_ps();
    let mut acc1 = _mm512_setzero_ps();
    let mut acc2 = _mm512_setzero_ps();
    let mut acc3 = _mm512_setzero_ps();

    let chunks = n / 64;
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    for i in 0..chunks {
        let offset = i * 64;
        let a0 = _mm512_loadu_ps(a_ptr.add(offset));
        let b0 = _mm512_loadu_ps(b_ptr.add(offset));
        let d0 = _mm512_sub_ps(a0, b0);
        acc0 = _mm512_fmadd_ps(d0, d0, acc0);

        let a1 = _mm512_loadu_ps(a_ptr.add(offset + 16));
        let b1 = _mm512_loadu_ps(b_ptr.add(offset + 16));
        let d1 = _mm512_sub_ps(a1, b1);
        acc1 = _mm512_fmadd_ps(d1, d1, acc1);

        let a2 = _mm512_loadu_ps(a_ptr.add(offset + 32));
        let b2 = _mm512_loadu_ps(b_ptr.add(offset + 32));
        let d2 = _mm512_sub_ps(a2, b2);
        acc2 = _mm512_fmadd_ps(d2, d2, acc2);

        let a3 = _mm512_loadu_ps(a_ptr.add(offset + 48));
        let b3 = _mm512_loadu_ps(b_ptr.add(offset + 48));
        let d3 = _mm512_sub_ps(a3, b3);
        acc3 = _mm512_fmadd_ps(d3, d3, acc3);
    }

    acc0 = _mm512_add_ps(acc0, acc2);
    acc1 = _mm512_add_ps(acc1, acc3);
    acc0 = _mm512_add_ps(acc0, acc1);

    let mut sum = _mm512_reduce_add_ps(acc0);
    let remainder_start = chunks * 64;
    for i in remainder_start..n {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Number of IVF clusters (centroids). More clusters = faster search but needs
// more probes for good recall. With 1M vectors, 4096 gives ~244 vecs/cluster on average.
const N_CLUSTERS: usize = 4096;
// Number of probes during search. Higher = better recall, slower.
// We'll tune this to hit >= 95% recall.
const N_PROBES: usize = 64;
// Minimum vectors before we switch from brute-force to IVF
const MIN_VECTORS_FOR_IVF: usize = 10000;

/// Wrapper for f32 that implements Ord via bit comparison (NaN-free assumption)
#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);

impl Eq for OrdF32 {}

impl PartialOrd for OrdF32 {
    #[inline]
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for OrdF32 {
    #[inline]
    fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

/// Entry in a max-heap for top-k tracking
#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry {
    dist: OrdF32,
    id: u64,
}

impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering {
        self.dist.cmp(&other.dist)
    }
}

/// All vector data stored in a flat, cache-friendly layout.
/// vectors: [id0_f0, id0_f1, ..., id0_f127, id1_f0, ...]
struct VectorStore {
    data: Vec<f32>,      // flat: n_vectors * 128
    ids: Vec<u64>,       // parallel id array
}

impl VectorStore {
    fn new() -> Self {
        VectorStore {
            data: Vec::new(),
            ids: Vec::new(),
        }
    }

    fn len(&self) -> usize {
        self.ids.len()
    }

    #[inline(always)]
    fn get_vec(&self, idx: usize) -> &[f32] {
        let start = idx * 128;
        &self.data[start..start + 128]
    }

    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.data.extend_from_slice(vector);
    }
}

/// IVF index: centroid array + inverted lists (which vector indices belong to each cluster)
struct IvfIndex {
    /// Flat centroids: N_CLUSTERS * 128 f32
    centroids: Vec<f32>,
    /// Inverted lists: centroid_id -> list of vector store indices
    lists: Vec<Vec<u32>>,
    /// Whether the index has been built
    built: bool,
}

impl IvfIndex {
    fn new() -> Self {
        IvfIndex {
            centroids: Vec::new(),
            lists: vec![Vec::new(); N_CLUSTERS],
            built: false,
        }
    }

    #[inline(always)]
    fn centroid(&self, idx: usize) -> &[f32] {
        let start = idx * 128;
        &self.centroids[start..start + 128]
    }

    /// Find the N_PROBES nearest centroids to query, returns their indices sorted by distance
    fn nearest_centroids(&self, query: &[f32], n_probes: usize) -> Vec<usize> {
        let n = self.centroids.len() / 128;
        let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(n_probes + 1);

        for i in 0..n {
            let d = l2_distance_f32(query, self.centroid(i));
            let entry = HeapEntry { dist: OrdF32(d), id: i as u64 };
            if heap.len() < n_probes {
                heap.push(entry);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(entry);
            }
        }

        let mut result: Vec<usize> = heap.into_iter().map(|e| e.id as usize).collect();
        result.sort_unstable_by(|&a, &b| {
            let da = l2_distance_f32(query, self.centroid(a));
            let db = l2_distance_f32(query, self.centroid(b));
            da.partial_cmp(&db).unwrap_or(Ordering::Equal)
        });
        result
    }
}

pub struct VectorDB {
    /// RwLock protecting the vector store and IVF index
    inner: RwLock<Inner>,
}

struct Inner {
    store: VectorStore,
    ivf: IvfIndex,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                store: VectorStore::new(),
                ivf: IvfIndex::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        inner.store.push(id, &vector);
        inner.ivf.built = false; // invalidate index
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut inner = self.inner.write();
        for (id, vec) in vectors {
            inner.store.push(id, &vec);
        }
        // Build IVF index if we have enough vectors
        if inner.store.len() >= MIN_VECTORS_FOR_IVF {
            build_ivf(&mut inner);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.store.len();
        if n == 0 {
            return Vec::new();
        }
        let k = top_k as usize;

        if inner.ivf.built && n >= MIN_VECTORS_FOR_IVF {
            search_ivf(&inner, vector, k)
        } else {
            search_brute_force(&inner.store, vector, k)
        }
    }
}

/// Build the IVF index using k-means clustering on the stored vectors.
fn build_ivf(inner: &mut Inner) {
    let n = inner.store.len();
    let n_clusters = N_CLUSTERS.min(n);

    eprintln!("Building IVF index with {} clusters on {} vectors...", n_clusters, n);

    // Initialize centroids by sampling evenly-spaced vectors
    let mut centroids = Vec::<f32>::with_capacity(n_clusters * 128);
    let step = n / n_clusters;
    for i in 0..n_clusters {
        let idx = i * step;
        centroids.extend_from_slice(inner.store.get_vec(idx));
    }

    // k-means iterations
    let n_iters = 20;
    let mut assignments = vec![0u32; n];

    for _iter in 0..n_iters {
        // Assignment step: assign each vector to nearest centroid (parallel)
        let store_data = &inner.store.data;
        let centroids_ref = &centroids;
        let new_assignments: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                let v = &store_data[i * 128..(i + 1) * 128];
                let mut best_dist = f32::MAX;
                let mut best_c = 0u32;
                for c in 0..n_clusters {
                    let cen = &centroids_ref[c * 128..(c + 1) * 128];
                    let d = l2_distance_f32(v, cen);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            })
            .collect();

        let changed = assignments.iter().zip(new_assignments.iter()).filter(|(a, b)| a != b).count();
        assignments = new_assignments;

        // Update step: recompute centroids
        let mut sums = vec![0.0f64; n_clusters * 128];
        let mut counts = vec![0u64; n_clusters];

        for i in 0..n {
            let c = assignments[i] as usize;
            counts[c] += 1;
            let v = inner.store.get_vec(i);
            let sum_slice = &mut sums[c * 128..(c + 1) * 128];
            for j in 0..128 {
                sum_slice[j] += v[j] as f64;
            }
        }

        for c in 0..n_clusters {
            let cnt = counts[c].max(1) as f64;
            let cen = &mut centroids[c * 128..(c + 1) * 128];
            let sum_slice = &sums[c * 128..(c + 1) * 128];
            for j in 0..128 {
                cen[j] = (sum_slice[j] / cnt) as f32;
            }
        }

        eprintln!("  k-means iter {}/{}: {} reassignments", _iter + 1, n_iters, changed);
        if changed == 0 {
            break;
        }
    }

    // Build inverted lists
    let mut lists: Vec<Vec<u32>> = vec![Vec::new(); n_clusters];
    for (i, &c) in assignments.iter().enumerate() {
        lists[c as usize].push(i as u32);
    }

    inner.ivf.centroids = centroids;
    inner.ivf.lists = lists;
    inner.ivf.built = true;

    eprintln!("IVF index built.");
}

/// Brute-force search over all vectors (parallel across 4 chunks)
fn search_brute_force(store: &VectorStore, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n = store.len();
    let k = k.min(n);

    // Split into 4 chunks for parallel processing
    let chunk_size = (n + 3) / 4;

    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|chunk_id| {
            let start = chunk_id * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end {
                return Vec::new();
            }
            let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
            for i in start..end {
                let v = store.get_vec(i);
                let d = l2_distance_f32(query, v);
                let entry = HeapEntry { dist: OrdF32(d), id: store.ids[i] };
                if heap.len() < k {
                    heap.push(entry);
                } else if d < heap.peek().unwrap().dist.0 {
                    heap.pop();
                    heap.push(entry);
                }
            }
            heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
        })
        .collect();

    // Merge results from chunks
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for chunk in results {
        for (d, id) in chunk {
            let entry = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k {
                heap.push(entry);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(entry);
            }
        }
    }

    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

/// IVF search: probe nearest centroids and search their lists
fn search_ivf(inner: &Inner, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n_probes = N_PROBES.min(N_CLUSTERS);
    let probe_list = inner.ivf.nearest_centroids(query, n_probes);

    // Collect all candidate vector indices from probed lists
    let mut candidates: Vec<u32> = Vec::new();
    for &cid in &probe_list {
        candidates.extend_from_slice(&inner.ivf.lists[cid]);
    }

    // Search candidates (in parallel chunks)
    let n = candidates.len();
    let k = k.min(n);
    if k == 0 {
        return Vec::new();
    }

    // Use parallel search over candidates
    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|chunk_id| {
            let start = chunk_id * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end {
                return Vec::new();
            }
            let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
            for i in start..end {
                let idx = candidates[i] as usize;
                let v = inner.store.get_vec(idx);
                let d = l2_distance_f32(query, v);
                let entry = HeapEntry { dist: OrdF32(d), id: inner.store.ids[idx] };
                if heap.len() < k {
                    heap.push(entry);
                } else if d < heap.peek().unwrap().dist.0 {
                    heap.pop();
                    heap.push(entry);
                }
            }
            heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
        })
        .collect();

    // Merge
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for chunk in results {
        for (d, id) in chunk {
            let entry = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k {
                heap.push(entry);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(entry);
            }
        }
    }

    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Number of IVF clusters. With 1M vectors: 2048 clusters -> ~488 vecs/cluster.
const N_CLUSTERS: usize = 2048;
// Number of probes during search.
const N_PROBES: usize = 48;
// k-means iterations
const KMEANS_ITERS: usize = 15;
// Minimum vectors before switching from brute-force to IVF
const MIN_VECTORS_FOR_IVF: usize = 10_000;

/// Wrapper for f32 that implements Ord
#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);

impl Eq for OrdF32 {}

impl PartialOrd for OrdF32 {
    #[inline]
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for OrdF32 {
    #[inline]
    fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

/// Entry in a max-heap for top-k tracking
#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry {
    dist: OrdF32,
    id: u64,
}

impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering {
        self.dist.cmp(&other.dist)
    }
}

/// All vector data stored in a flat, cache-friendly layout.
struct VectorStore {
    data: Vec<f32>,   // flat: n_vectors * 128
    ids: Vec<u64>,    // parallel id array
}

impl VectorStore {
    fn new() -> Self {
        VectorStore {
            data: Vec::new(),
            ids: Vec::new(),
        }
    }

    fn len(&self) -> usize {
        self.ids.len()
    }

    #[inline(always)]
    fn get_vec(&self, idx: usize) -> &[f32] {
        let start = idx * 128;
        &self.data[start..start + 128]
    }

    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.data.extend_from_slice(vector);
    }
}

/// IVF index
struct IvfIndex {
    /// Flat centroids: N_CLUSTERS * 128 f32
    centroids: Vec<f32>,
    /// Inverted lists: centroid_id -> list of vector store indices
    lists: Vec<Vec<u32>>,
    /// Whether the index is valid
    built: bool,
}

impl IvfIndex {
    fn new() -> Self {
        IvfIndex {
            centroids: Vec::new(),
            lists: Vec::new(),
            built: false,
        }
    }

    #[inline(always)]
    fn centroid(&self, idx: usize) -> &[f32] {
        let start = idx * 128;
        &self.centroids[start..start + 128]
    }

    /// Find the n_probes nearest centroids to query
    fn nearest_centroids(&self, query: &[f32], n_probes: usize) -> Vec<usize> {
        let n = self.centroids.len() / 128;

        // Parallel search over centroids split into 4 chunks
        let chunk_size = (n + 3) / 4;
        let per_chunk: Vec<Vec<(f32, usize)>> = (0..4)
            .into_par_iter()
            .map(|ci| {
                let start = ci * chunk_size;
                let end = (start + chunk_size).min(n);
                if start >= end { return Vec::new(); }
                let mut local: Vec<(f32, usize)> = Vec::with_capacity(n_probes + 1);
                let mut worst = f32::MAX;
                for i in start..end {
                    let d = l2_distance_f32(query, self.centroid(i));
                    if local.len() < n_probes {
                        local.push((d, i));
                        if local.len() == n_probes {
                            worst = local.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                        }
                    } else if d < worst {
                        // Replace worst
                        let idx = local.iter().position(|x| x.0 == worst).unwrap_or(0);
                        local[idx] = (d, i);
                        worst = local.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                    }
                }
                local
            })
            .collect();

        // Merge
        let mut all: Vec<(f32, usize)> = per_chunk.into_iter().flatten().collect();
        all.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
        all.truncate(n_probes);
        all.into_iter().map(|(_, idx)| idx).collect()
    }
}

pub struct VectorDB {
    inner: RwLock<Inner>,
}

struct Inner {
    store: VectorStore,
    ivf: IvfIndex,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                store: VectorStore::new(),
                ivf: IvfIndex::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        inner.store.push(id, &vector);
        inner.ivf.built = false;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut inner = self.inner.write();
            for (id, vec) in vectors {
                inner.store.push(id, &vec);
            }
        }
        // Build IVF index (outside of write lock scope above, re-acquire)
        {
            let n = self.inner.read().store.len();
            if n >= MIN_VECTORS_FOR_IVF {
                let mut inner = self.inner.write();
                build_ivf(&mut inner);
            }
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.store.len();
        if n == 0 {
            return Vec::new();
        }
        let k = top_k as usize;

        if inner.ivf.built && n >= MIN_VECTORS_FOR_IVF {
            search_ivf(&inner, vector, k)
        } else {
            search_brute_force(&inner.store, vector, k)
        }
    }
}

/// Build the IVF index using k-means on the stored vectors.
fn build_ivf(inner: &mut Inner) {
    let n = inner.store.len();
    let n_clusters = N_CLUSTERS.min(n);

    eprintln!("Building IVF index: {} clusters, {} vectors", n_clusters, n);

    // Initialize centroids: sample evenly
    let mut centroids = Vec::<f32>::with_capacity(n_clusters * 128);
    let step = n / n_clusters;
    for i in 0..n_clusters {
        let idx = i * step;
        centroids.extend_from_slice(inner.store.get_vec(idx));
    }

    let mut assignments = vec![0u32; n];

    for iter in 0..KMEANS_ITERS {
        // Parallel assignment
        let store_data = &inner.store.data;
        let centroids_snap = centroids.clone();
        let new_assignments: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                let v = &store_data[i * 128..(i + 1) * 128];
                let mut best_dist = f32::MAX;
                let mut best_c = 0u32;
                for c in 0..n_clusters {
                    let cen = &centroids_snap[c * 128..(c + 1) * 128];
                    let d = l2_distance_f32(v, cen);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            })
            .collect();

        let changed = assignments
            .iter()
            .zip(new_assignments.iter())
            .filter(|(a, b)| a != b)
            .count();
        assignments = new_assignments;

        // Update centroids
        // Use parallel reduction per cluster
        // Accumulate with f64 for stability
        let mut sums = vec![0.0f64; n_clusters * 128];
        let mut counts = vec![0u32; n_clusters];

        for i in 0..n {
            let c = assignments[i] as usize;
            counts[c] += 1;
            let v = inner.store.get_vec(i);
            let sum_slice = &mut sums[c * 128..(c + 1) * 128];
            for j in 0..128 {
                sum_slice[j] += v[j] as f64;
            }
        }

        for c in 0..n_clusters {
            let cnt = (counts[c] as f64).max(1.0);
            let cen = &mut centroids[c * 128..(c + 1) * 128];
            let sum_slice = &sums[c * 128..(c + 1) * 128];
            for j in 0..128 {
                cen[j] = (sum_slice[j] / cnt) as f32;
            }
        }

        eprintln!("  iter {}/{}: {} changed", iter + 1, KMEANS_ITERS, changed);
        if changed == 0 {
            break;
        }
    }

    // Build inverted lists
    let mut lists: Vec<Vec<u32>> = vec![Vec::new(); n_clusters];
    for (i, &c) in assignments.iter().enumerate() {
        lists[c as usize].push(i as u32);
    }

    inner.ivf.centroids = centroids;
    inner.ivf.lists = lists;
    inner.ivf.built = true;

    let avg_list_size = n / n_clusters;
    eprintln!("IVF built. Avg list size: {}", avg_list_size);
}

/// Brute-force search (parallel across 4 threads)
fn search_brute_force(store: &VectorStore, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n = store.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|chunk_id| {
            let start = chunk_id * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }
            top_k_in_range(&store.data, &store.ids, start, end, query, k)
        })
        .collect();

    merge_results(results, k)
}

/// IVF search: probe nearest centroids and search their lists
fn search_ivf(inner: &Inner, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n_probes = N_PROBES;
    let probe_list = inner.ivf.nearest_centroids(query, n_probes);

    // Gather candidate indices
    let mut candidates: Vec<u32> = Vec::new();
    for &cid in &probe_list {
        candidates.extend_from_slice(&inner.ivf.lists[cid]);
    }

    let n = candidates.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    // Search candidates in parallel chunks
    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|chunk_id| {
            let start = chunk_id * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }

            let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
            for i in start..end {
                let idx = candidates[i] as usize;
                let v = inner.store.get_vec(idx);
                let d = l2_distance_f32(query, v);
                let entry = HeapEntry { dist: OrdF32(d), id: inner.store.ids[idx] };
                if heap.len() < k {
                    heap.push(entry);
                } else if d < heap.peek().unwrap().dist.0 {
                    heap.pop();
                    heap.push(entry);
                }
            }
            heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
        })
        .collect();

    merge_results(results, k)
}

/// Find top-k in a contiguous range of the flat data array
#[inline]
fn top_k_in_range(
    data: &[f32],
    ids: &[u64],
    start: usize,
    end: usize,
    query: &[f32],
    k: usize,
) -> Vec<(f32, u64)> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for i in start..end {
        let v = &data[i * 128..(i + 1) * 128];
        let d = l2_distance_f32(query, v);
        let entry = HeapEntry { dist: OrdF32(d), id: ids[i] };
        if heap.len() < k {
            heap.push(entry);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(entry);
        }
    }
    heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
}

/// Merge results from parallel chunks into final sorted top-k
fn merge_results(chunks: Vec<Vec<(f32, u64)>>, k: usize) -> Vec<SearchResult> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for chunk in chunks {
        for (d, id) in chunk {
            let entry = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k {
                heap.push(entry);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(entry);
            }
        }
    }

    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters
const N_CLUSTERS: usize = 1024;
const N_PROBES: usize = 32;
const KMEANS_ITERS: usize = 10;
const MIN_VECTORS_FOR_IVF: usize = 10_000;

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);

impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for OrdF32 {
    #[inline] fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry { dist: OrdF32, id: u64 }
impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering { self.dist.cmp(&other.dist) }
}

struct VectorStore {
    data: Vec<f32>,
    ids: Vec<u64>,
}

impl VectorStore {
    fn new() -> Self { VectorStore { data: Vec::new(), ids: Vec::new() } }
    fn len(&self) -> usize { self.ids.len() }
    #[inline(always)] fn get_vec(&self, idx: usize) -> &[f32] {
        &self.data[idx * 128..(idx + 1) * 128]
    }
    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.data.extend_from_slice(vector);
    }
}

struct IvfIndex {
    centroids: Vec<f32>,          // N_CLUSTERS * 128
    lists: Vec<Vec<u32>>,         // cluster -> [vector indices]
    built: bool,
}

impl IvfIndex {
    fn new() -> Self { IvfIndex { centroids: Vec::new(), lists: Vec::new(), built: false } }
    #[inline(always)] fn centroid(&self, idx: usize) -> &[f32] {
        &self.centroids[idx * 128..(idx + 1) * 128]
    }
}

pub struct VectorDB {
    inner: RwLock<Inner>,
}

struct Inner {
    store: VectorStore,
    ivf: IvfIndex,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                store: VectorStore::new(),
                ivf: IvfIndex::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        inner.store.push(id, &vector);
        inner.ivf.built = false;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut inner = self.inner.write();
        for (id, vec) in vectors {
            inner.store.push(id, &vec);
        }
        if inner.store.len() >= MIN_VECTORS_FOR_IVF {
            build_ivf(&mut inner);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.store.len();
        if n == 0 { return Vec::new(); }
        let k = top_k as usize;
        if inner.ivf.built {
            search_ivf(&inner, vector, k)
        } else {
            search_brute_force(&inner.store, vector, k)
        }
    }
}

fn build_ivf(inner: &mut Inner) {
    let n = inner.store.len();
    let n_clusters = N_CLUSTERS.min(n);
    eprintln!("Building IVF: {} clusters, {} vecs", n_clusters, n);

    // Init centroids: evenly spaced sample
    let mut centroids = Vec::<f32>::with_capacity(n_clusters * 128);
    let step = n / n_clusters;
    for i in 0..n_clusters {
        centroids.extend_from_slice(inner.store.get_vec(i * step));
    }

    let mut assignments = vec![0u32; n];

    for iter in 0..KMEANS_ITERS {
        // --- Assignment step (parallel) ---
        let store_data_ptr = inner.store.data.as_ptr() as usize;
        let centroids_ptr = centroids.as_ptr() as usize;
        let n_clusters_c = n_clusters;

        let new_assignments: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                let store_ptr = store_data_ptr as *const f32;
                let cen_ptr = centroids_ptr as *const f32;
                let v = unsafe { std::slice::from_raw_parts(store_ptr.add(i * 128), 128) };
                let mut best_dist = f32::MAX;
                let mut best_c = 0u32;
                for c in 0..n_clusters_c {
                    let cen = unsafe { std::slice::from_raw_parts(cen_ptr.add(c * 128), 128) };
                    let d = l2_distance_f32(v, cen);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            })
            .collect();

        let changed = assignments.iter().zip(new_assignments.iter()).filter(|(a,b)| a!=b).count();
        assignments = new_assignments;

        // --- Update step ---
        let mut sums = vec![0.0f64; n_clusters * 128];
        let mut counts = vec![0u32; n_clusters];

        for i in 0..n {
            let c = assignments[i] as usize;
            counts[c] += 1;
            let v = inner.store.get_vec(i);
            let s = &mut sums[c * 128..(c + 1) * 128];
            for j in 0..128 { s[j] += v[j] as f64; }
        }

        for c in 0..n_clusters {
            let cnt = (counts[c] as f64).max(1.0);
            let cen = &mut centroids[c * 128..(c + 1) * 128];
            let s = &sums[c * 128..(c + 1) * 128];
            for j in 0..128 { cen[j] = (s[j] / cnt) as f32; }
        }

        eprintln!("  k-means {}/{}: {} changes", iter+1, KMEANS_ITERS, changed);
        if changed == 0 { break; }
    }

    // Build inverted lists
    let mut lists: Vec<Vec<u32>> = (0..n_clusters).map(|_| Vec::new()).collect();
    for (i, &c) in assignments.iter().enumerate() {
        lists[c as usize].push(i as u32);
    }

    inner.ivf.centroids = centroids;
    inner.ivf.lists = lists;
    inner.ivf.built = true;
    eprintln!("IVF done. Avg list size: {}", n / n_clusters);
}

fn nearest_centroids(ivf: &IvfIndex, query: &[f32], n_probes: usize) -> Vec<usize> {
    let n = ivf.centroids.len() / 128;
    // Parallel over 4 chunks
    let chunk_size = (n + 3) / 4;
    let cen_ptr = ivf.centroids.as_ptr() as usize;

    let per_chunk: Vec<Vec<(f32, usize)>> = (0..4)
        .into_par_iter()
        .map(|ci| {
            let start = ci * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }
            let ptr = cen_ptr as *const f32;
            let mut best: Vec<(f32, usize)> = Vec::with_capacity(n_probes + 1);
            let mut worst = f32::MAX;
            for i in start..end {
                let cen = unsafe { std::slice::from_raw_parts(ptr.add(i * 128), 128) };
                let d = l2_distance_f32(query, cen);
                if best.len() < n_probes {
                    best.push((d, i));
                    if best.len() == n_probes {
                        worst = best.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                    }
                } else if d < worst {
                    let pos = best.iter().position(|x| x.0 == worst).unwrap_or(0);
                    best[pos] = (d, i);
                    worst = best.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                }
            }
            best
        })
        .collect();

    let mut all: Vec<(f32, usize)> = per_chunk.into_iter().flatten().collect();
    all.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
    all.truncate(n_probes);
    all.into_iter().map(|(_, i)| i).collect()
}

fn search_brute_force(store: &VectorStore, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n = store.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }
    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|ci| {
            let start = ci * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }
            top_k_range(&store.data, &store.ids, start, end, query, k)
        })
        .collect();
    merge_and_sort(results, k)
}

fn search_ivf(inner: &Inner, query: &[f32], k: usize) -> Vec<SearchResult> {
    let probes = nearest_centroids(&inner.ivf, query, N_PROBES);
    let mut candidates: Vec<u32> = Vec::new();
    for &cid in &probes {
        candidates.extend_from_slice(&inner.ivf.lists[cid]);
    }
    let n = candidates.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    // Sequential scan over candidates (usually ~30-50k)
    let store = &inner.store;
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for &idx in &candidates {
        let idx = idx as usize;
        let v = store.get_vec(idx);
        let d = l2_distance_f32(query, v);
        let e = HeapEntry { dist: OrdF32(d), id: store.ids[idx] };
        if heap.len() < k {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }

    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

#[inline]
fn top_k_range(data: &[f32], ids: &[u64], start: usize, end: usize, query: &[f32], k: usize) -> Vec<(f32, u64)> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for i in start..end {
        let v = &data[i * 128..(i + 1) * 128];
        let d = l2_distance_f32(query, v);
        let e = HeapEntry { dist: OrdF32(d), id: ids[i] };
        if heap.len() < k {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }
    heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
}

fn merge_and_sort(chunks: Vec<Vec<(f32, u64)>>, k: usize) -> Vec<SearchResult> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for chunk in chunks {
        for (d, id) in chunk {
            let e = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k {
                heap.push(e);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(e);
            }
        }
    }
    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters — tuned for 1M vectors, 4 cores
// 2048 clusters: assignment cost = 1M * 2048 * 128 floats per iter
// Use fewer clusters to make build fast, more probes to keep recall high
const N_CLUSTERS: usize = 4096;
const N_PROBES: usize = 80;
const KMEANS_ITERS: usize = 20;

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);

impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
