/// Build IVF index. The bottleneck is the assignment step: for each of the 1M vectors
/// we compute distances to all N_CLUSTERS centroids. We speed this up by:
/// 1. Fully parallelizing the assignment step across all 4 cores.
/// 2. Using our fast AVX-512 SIMD distance function.
fn build_ivf(inner: &mut Inner) {
    let n = inner.store.len();
    let n_clusters = N_CLUSTERS.min(n);
    eprintln!("[IVF] Building: {} clusters, {} vectors", n_clusters, n);

    // Init centroids: evenly spaced sample across the dataset
    let mut centroids: Vec<f32> = Vec::with_capacity(n_clusters * 128);
    let step = n / n_clusters;
    for i in 0..n_clusters {
        centroids.extend_from_slice(inner.store.get_vec(i * step));
    }

    let mut assignments = vec![0u32; n];

    for iter in 0..KMEANS_ITERS {
        // --- Parallel assignment step ---
        // We pass raw pointers to avoid clone/lifetime issues in parallel closures.
        // SAFETY: store.data and centroids are not mutated during this block.
        let store_ptr = inner.store.data.as_ptr() as usize;
        let cen_ptr = centroids.as_ptr() as usize;

        let new_asgn: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                // SAFETY: read-only access, disjoint indices per thread
                let v = unsafe {
                    std::slice::from_raw_parts((store_ptr as *const f32).add(i * 128), 128)
                };
                let mut best_d = f32::MAX;
                let mut best_c = 0u32;
                for c in 0..n_clusters {
                    let cen = unsafe {
                        std::slice::from_raw_parts((cen_ptr as *const f32).add(c * 128), 128)
                    };
                    let d = l2_distance_f32(v, cen);
                    if d < best_d { best_d = d; best_c = c as u32; }
                }
                best_c
            })
            .collect();

        let changed = assignments.iter().zip(&new_asgn).filter(|(a, b)| a != b).count();
        assignments = new_asgn;

        // --- Update centroids (sequential) ---
        let mut sums = vec![0.0f32; n_clusters * 128];
        let mut counts = vec![0u32; n_clusters];
        for i in 0..n {
            let c = assignments[i] as usize;
            counts[c] += 1;
            let v = inner.store.get_vec(i);
            let s = &mut sums[c * 128..(c + 1) * 128];
            for j in 0..128 { s[j] += v[j]; }
        }
        for c in 0..n_clusters {
            let cnt = counts[c].max(1) as f32;
            let cen = &mut centroids[c * 128..(c + 1) * 128];
            let s = &sums[c * 128..(c + 1) * 128];
            for j in 0..128 { cen[j] = s[j] / cnt; }
        }

        eprintln!("[IVF] iter {}/{}: {} changed", iter + 1, KMEANS_ITERS, changed);
        if changed == 0 { break; }
    }

    // Build inverted lists
    let mut lists: Vec<Vec<u32>> = (0..n_clusters).map(|_| Vec::new()).collect();
    for (i, &c) in assignments.iter().enumerate() {
        lists[c as usize].push(i as u32);
    }

    inner.ivf.centroids = centroids;
    inner.ivf.lists = lists;
    inner.ivf.built = true;

    eprintln!("[IVF] Done. Avg list size: {}", n / n_clusters);
}

/// Find the n_probes nearest centroids (sequential linear scan — only 2048 centroids)
fn nearest_centroids(ivf: &IvfIndex, query: &[f32], n_probes: usize) -> Vec<usize> {
    let n = ivf.centroids.len() / 128;
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(n_probes + 1);
    for i in 0..n {
        let cen = &ivf.centroids[i * 128..(i + 1) * 128];
        let d = l2_distance_f32(query, cen);
        let e = HeapEntry { dist: OrdF32(d), id: i as u64 };
        if heap.len() < n_probes {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }
    let mut v: Vec<(f32, usize)> = heap.into_iter().map(|e| (e.dist.0, e.id as usize)).collect();
    v.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
    v.into_iter().map(|(_, i)| i).collect()
}

fn search_brute_force(store: &VectorStore, query: &[f32], k: usize) -> Vec<SearchResult> {
    let n = store.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }
    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|ci| {
            let start = ci * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }
            top_k_range(&store.data, &store.ids, start, end, query, k)
        })
        .collect();
    merge_and_sort(results, k)
}

fn search_ivf(inner: &Inner, query: &[f32], k: usize) -> Vec<SearchResult> {
    let probes = nearest_centroids(&inner.ivf, query, N_PROBES);
    let mut candidates: Vec<u32> = Vec::new();
    for &cid in &probes {
        candidates.extend_from_slice(&inner.ivf.lists[cid]);
    }
    let n = candidates.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    let store = &inner.store;
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for &idx in &candidates {
        let idx = idx as usize;
        let v = store.get_vec(idx);
        let d = l2_distance_f32(query, v);
        let e = HeapEntry { dist: OrdF32(d), id: store.ids[idx] };
        if heap.len() < k {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
