use parking_lot::{RwLock, Mutex};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;
use std::sync::Arc;

// IVF parameters
// We use fewer iterations with a good init to speed up building.
// With AVX-512 on 4 cores: should be fast enough.
const N_CLUSTERS: usize = 1024;
const N_PROBES: usize = 50;
const KMEANS_ITERS: usize = 5;

// Rayon's global thread pool gets initialized to #CPUs. We want to cap at 4.
// We'll configure via RAYON_NUM_THREADS env var or just let it be.

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);
impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for OrdF32 {
    #[inline] fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry { dist: OrdF32, id: u64 }
impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering { self.dist.cmp(&other.dist) }
}

pub struct VectorDB {
    store_data: RwLock<Vec<f32>>,   // flat: n * 128
    store_ids: RwLock<Vec<u64>>,
    ivf: RwLock<Option<IvfIndex>>,
}

struct IvfIndex {
    centroids: Vec<f32>,   // n_clusters * 128
    lists: Vec<Vec<u32>>,  // cluster -> [vector indices]
    n_clusters: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            store_data: RwLock::new(Vec::new()),
            store_ids: RwLock::new(Vec::new()),
            ivf: RwLock::new(None),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        {
            let mut data = self.store_data.write();
            data.extend_from_slice(&vector);
        }
        {
            let mut ids = self.store_ids.write();
            ids.push(id);
        }
        // Invalidate index
        *self.ivf.write() = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut data = self.store_data.write();
            let mut ids = self.store_ids.write();
            data.reserve(count * 128);
            ids.reserve(count);
            for (id, vec) in &vectors {
                data.extend_from_slice(vec);
                ids.push(*id);
            }
        }
        // Build IVF
        self.rebuild_ivf();
        count
    }

    fn rebuild_ivf(&self) {
        let (data, ids_len) = {
            let data = self.store_data.read();
            let ids = self.store_ids.read();
            (data.clone(), ids.len())
        };

        if ids_len < 100 { return; }

        let ivf = build_ivf_from_data(&data, ids_len, N_CLUSTERS, KMEANS_ITERS);
        *self.ivf.write() = Some(ivf);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.store_ids.read();
        let n = ids.len();
        if n == 0 { return Vec::new(); }
        let k = top_k as usize;

        let ivf_guard = self.ivf.read();
        if let Some(ivf) = ivf_guard.as_ref() {
            let data = self.store_data.read();
            search_ivf_inner(&data, &ids, ivf, vector, k)
        } else {
            let data = self.store_data.read();
            search_brute_force_inner(&data, &ids, vector, k)
        }
    }
}

fn build_ivf_from_data(data: &[f32], n: usize, n_clusters: usize, n_iters: usize) -> IvfIndex {
    let n_clusters = n_clusters.min(n);
    eprintln!("[IVF] Building: {} clusters, {} vectors", n_clusters, n);
    let t0 = std::time::Instant::now();

    // Init centroids: evenly spaced
    let step = n / n_clusters;
    let mut centroids: Vec<f32> = Vec::with_capacity(n_clusters * 128);
    for i in 0..n_clusters {
        let start = i * step * 128;
        centroids.extend_from_slice(&data[start..start + 128]);
    }

    let mut assignments = vec![0u32; n];

    for iter in 0..n_iters {
        let t1 = std::time::Instant::now();

        // Parallel assignment
        let store_ptr = data.as_ptr() as usize;
        let cen_ptr = centroids.as_ptr() as usize;
        let nc = n_clusters;

        let new_asgn: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                let v = unsafe {
                    std::slice::from_raw_parts((store_ptr as *const f32).add(i * 128), 128)
                };
                let mut best_d = f32::MAX;
                let mut best_c = 0u32;
                for c in 0..nc {
                    let cen = unsafe {
                        std::slice::from_raw_parts((cen_ptr as *const f32).add(c * 128), 128)
                    };
                    let d = l2_distance_f32(v, cen);
                    if d < best_d { best_d = d; best_c = c as u32; }
                }
                best_c
            })
            .collect();

        let changed = assignments.iter().zip(&new_asgn).filter(|(a, b)| a != b).count();
        assignments = new_asgn;

        // Update centroids
        let mut sums = vec![0.0f32; n_clusters * 128];
        let mut counts = vec![0u32; n_clusters];
        for i in 0..n {
            let c = assignments[i] as usize;
            counts[c] += 1;
            let v = &data[i * 128..(i + 1) * 128];
            let s = &mut sums[c * 128..(c + 1) * 128];
            for j in 0..128 { s[j] += v[j]; }
        }
        for c in 0..n_clusters {
            let cnt = counts[c].max(1) as f32;
            let cen = &mut centroids[c * 128..(c + 1) * 128];
            let s = &sums[c * 128..(c + 1) * 128];
            for j in 0..128 { cen[j] = s[j] / cnt; }
        }

        eprintln!("[IVF] iter {}/{}: {} changed ({:.1}s)", 
            iter + 1, n_iters, changed, t1.elapsed().as_secs_f64());
        if changed == 0 { break; }
    }

    let mut lists: Vec<Vec<u32>> = (0..n_clusters).map(|_| Vec::new()).collect();
    for (i, &c) in assignments.iter().enumerate() {
        lists[c as usize].push(i as u32);
    }

    eprintln!("[IVF] Done in {:.1}s. Avg list: {}", 
        t0.elapsed().as_secs_f64(), n / n_clusters);

    IvfIndex { centroids, lists, n_clusters }
}

fn nearest_centroids_fn(ivf: &IvfIndex, query: &[f32], n_probes: usize) -> Vec<usize> {
    let n = ivf.n_clusters;
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(n_probes + 1);
    for i in 0..n {
        let cen = &ivf.centroids[i * 128..(i + 1) * 128];
        let d = l2_distance_f32(query, cen);
        let e = HeapEntry { dist: OrdF32(d), id: i as u64 };
        if heap.len() < n_probes {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }
    let mut v: Vec<(f32, usize)> = heap.into_iter().map(|e| (e.dist.0, e.id as usize)).collect();
    v.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
    v.into_iter().map(|(_, i)| i).collect()
}

fn search_ivf_inner(data: &[f32], ids: &[u64], ivf: &IvfIndex, query: &[f32], k: usize) -> Vec<SearchResult> {
    let probes = nearest_centroids_fn(ivf, query, N_PROBES);
    let mut candidates: Vec<u32> = Vec::new();
    for &cid in &probes {
        candidates.extend_from_slice(&ivf.lists[cid]);
    }
    let n = candidates.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for &idx in &candidates {
        let idx = idx as usize;
        let v = &data[idx * 128..(idx + 1) * 128];
        let d = l2_distance_f32(query, v);
        let e = HeapEntry { dist: OrdF32(d), id: ids[idx] };
        if heap.len() < k {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }

    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

fn search_brute_force_inner(data: &[f32], ids: &[u64], query: &[f32], k: usize) -> Vec<SearchResult> {
    let n = ids.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }
    let chunk_size = (n + 3) / 4;
    let results: Vec<Vec<(f32, u64)>> = (0..4)
        .into_par_iter()
        .map(|ci| {
            let start = ci * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }
            top_k_range_fn(data, ids, start, end, query, k)
        })
        .collect();
    merge_and_sort(results, k)
}

#[inline]
fn top_k_range_fn(data: &[f32], ids: &[u64], start: usize, end: usize, query: &[f32], k: usize) -> Vec<(f32, u64)> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for i in start..end {
        let v = &data[i * 128..(i + 1) * 128];
        let d = l2_distance_f32(query, v);
        let e = HeapEntry { dist: OrdF32(d), id: ids[i] };
        if heap.len() < k {
            heap.push(e);
        } else if d < heap.peek().unwrap().dist.0 {
            heap.pop();
            heap.push(e);
        }
    }
    heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
}

fn merge_and_sort(chunks: Vec<Vec<(f32, u64)>>, k: usize) -> Vec<SearchResult> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
    for chunk in chunks {
        for (d, id) in chunk {
            let e = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k {
                heap.push(e);
            } else if d < heap.peek().unwrap().dist.0 {
                heap.pop();
                heap.push(e);
            }
        }
    }
    let mut out: Vec<SearchResult> = heap
        .into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 })
        .collect();
    out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Conservative IVF: few clusters -> fast build, more probes -> good recall
// With 256 clusters on 1M: 3906 vecs/cluster, 64 probes = 250k candidates
// Build: 1M * 256 * few_iters assignments
const N_CLUSTERS: usize = 256;
const N_PROBES: usize = 64;
const KMEANS_ITERS: usize = 3;

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);
impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for OrdF32 {
    #[inline] fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry { dist: OrdF32, id: u64 }
impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering { self.dist.cmp(&other.dist) }
}

struct VectorStore {
    data: Vec<f32>,
    ids: Vec<u64>,
}

impl VectorStore {
    fn new() -> Self { VectorStore { data: Vec::new(), ids: Vec::new() } }
    fn len(&self) -> usize { self.ids.len() }
    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.data.extend_from_slice(vector);
    }
}

struct IvfIndex {
    centroids: Vec<f32>,
    lists: Vec<Vec<u32>>,
    n: usize,
}

pub struct VectorDB {
    inner: RwLock<Inner>,
}

struct Inner {
    store: VectorStore,
    ivf: Option<IvfIndex>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                store: VectorStore::new(),
                ivf: None,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut g = self.inner.write();
        g.store.push(id, &vector);
        g.ivf = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut g = self.inner.write();
        for (id, vec) in vectors {
            g.store.push(id, &vec);
        }
        let ivf = build_ivf(&g.store);
        g.ivf = Some(ivf);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let g = self.inner.read();
        let n = g.store.len();
        if n == 0 { return Vec::new(); }
        let k = top_k as usize;
        if let Some(ref ivf) = g.ivf {
            search_ivf(&g.store, ivf, vector, k)
        } else {
            search_brute(&g.store, vector, k)
        }
    }
}

fn build_ivf(store: &VectorStore) -> IvfIndex {
    let n = store.len();
    let nc = N_CLUSTERS.min(n);
    let t0 = std::time::Instant::now();
    eprintln!("[IVF] {nc} clusters, {n} vecs");

    let step = n / nc;
    let mut centroids: Vec<f32> = (0..nc)
        .flat_map(|i| store.data[i * step * 128..(i * step + 1) * 128].iter().copied())
        .collect();

    let mut asgn = vec![0u32; n];

    for iter in 0..KMEANS_ITERS {
        let sp = store.data.as_ptr() as usize;
        let cp = centroids.as_ptr() as usize;

        let new_asgn: Vec<u32> = (0..n).into_par_iter().map(|i| {
            let v = unsafe { std::slice::from_raw_parts((sp as *const f32).add(i*128), 128) };
            let mut bd = f32::MAX; let mut bc = 0u32;
            for c in 0..nc {
                let cen = unsafe { std::slice::from_raw_parts((cp as *const f32).add(c*128), 128) };
                let d = l2_distance_f32(v, cen);
                if d < bd { bd = d; bc = c as u32; }
            }
            bc
        }).collect();

        let chg = asgn.iter().zip(&new_asgn).filter(|(a,b)| a!=b).count();
        asgn = new_asgn;

        let mut sums = vec![0f32; nc * 128];
        let mut cnts = vec![0u32; nc];
        for i in 0..n {
            let c = asgn[i] as usize;
            cnts[c] += 1;
            let v = &store.data[i*128..(i+1)*128];
            let s = &mut sums[c*128..(c+1)*128];
            for j in 0..128 { s[j] += v[j]; }
        }
        for c in 0..nc {
            let cnt = cnts[c].max(1) as f32;
            let cen = &mut centroids[c*128..(c+1)*128];
            let s = &sums[c*128..(c+1)*128];
            for j in 0..128 { cen[j] = s[j] / cnt; }
        }
        eprintln!("[IVF] iter {}/{}: {} chg ({:.2}s)", iter+1, KMEANS_ITERS, chg, t0.elapsed().as_secs_f64());
        if chg == 0 { break; }
    }

    let mut lists: Vec<Vec<u32>> = (0..nc).map(|_| Vec::new()).collect();
    for (i, &c) in asgn.iter().enumerate() { lists[c as usize].push(i as u32); }

    eprintln!("[IVF] built in {:.2}s, avg list {}", t0.elapsed().as_secs_f64(), n/nc);
    IvfIndex { centroids, lists, n: nc }
}

fn nearest_n(ivf: &IvfIndex, q: &[f32], k: usize) -> Vec<usize> {
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for i in 0..ivf.n {
        let c = &ivf.centroids[i*128..(i+1)*128];
        let d = l2_distance_f32(q, c);
        let e = HeapEntry { dist: OrdF32(d), id: i as u64 };
        if heap.len() < k { heap.push(e); }
        else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
    }
    let mut v: Vec<_> = heap.into_iter().map(|e|(e.dist.0,e.id as usize)).collect();
    v.sort_unstable_by(|a,b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
    v.into_iter().map(|(_,i)| i).collect()
}

fn search_ivf(store: &VectorStore, ivf: &IvfIndex, q: &[f32], k: usize) -> Vec<SearchResult> {
    let probes = nearest_n(ivf, q, N_PROBES);
    let mut cands: Vec<u32> = Vec::new();
    for &cid in &probes { cands.extend_from_slice(&ivf.lists[cid]); }
    let n = cands.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for &idx in &cands {
        let idx = idx as usize;
        let v = &store.data[idx*128..(idx+1)*128];
        let d = l2_distance_f32(q, v);
        let e = HeapEntry { dist: OrdF32(d), id: store.ids[idx] };
        if heap.len() < k { heap.push(e); }
        else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
    }

    let mut out: Vec<SearchResult> = heap.into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 }).collect();
    out.sort_by(|a,b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

fn search_brute(store: &VectorStore, q: &[f32], k: usize) -> Vec<SearchResult> {
    let n = store.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }
    let cs = (n+3)/4;
    let res: Vec<_> = (0..4).into_par_iter().map(|ci| {
        let s = ci*cs; let e = (s+cs).min(n);
        if s >= e { return Vec::new(); }
        let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
        for i in s..e {
            let v = &store.data[i*128..(i+1)*128];
            let d = l2_distance_f32(q, v);
            let en = HeapEntry { dist: OrdF32(d), id: store.ids[i] };
            if heap.len() < k { heap.push(en); }
            else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(en); }
        }
        heap.into_iter().map(|e|(e.dist.0,e.id)).collect::<Vec<_>>()
    }).collect();

    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for chunk in res {
        for (d,id) in chunk {
            let e = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k { heap.push(e); }
            else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
        }
    }
    let mut out: Vec<SearchResult> = heap.into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 }).collect();
    out.sort_by(|a,b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

/// Compute squared L2 distance between two 128-dim f32 vectors.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_f32(a, b) as f64
}

/// Squared L2 distance as f32 (inner use).
#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    // Always use scalar — the compiler will auto-vectorize with target-cpu=native
    let mut s = 0.0f32;
    // Manual unroll for 128 dims
    let n = a.len();
    let mut i = 0;
    while i + 8 <= n {
        let d0 = a[i] - b[i];
        let d1 = a[i+1] - b[i+1];
        let d2 = a[i+2] - b[i+2];
        let d3 = a[i+3] - b[i+3];
        let d4 = a[i+4] - b[i+4];
        let d5 = a[i+5] - b[i+5];
        let d6 = a[i+6] - b[i+6];
        let d7 = a[i+7] - b[i+7];
        s += d0*d0 + d1*d1 + d2*d2 + d3*d3 + d4*d4 + d5*d5 + d6*d6 + d7*d7;
        i += 8;
    }
    while i < n {
        let d = a[i] - b[i];
        s += d * d;
        i += 1;
    }
    s
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters tuned for 1M/128-dim with 4 cores
// With few clusters, build is fast, probes compensate for lower quality.
// Target: build < 60s, recall >= 95%.
const N_CLUSTERS: usize = 256;
const N_PROBES: usize = 64;
const KMEANS_ITERS: usize = 3;

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);
impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for OrdF32 {
    #[inline] fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry { dist: OrdF32, id: u64 }
impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering { self.dist.cmp(&other.dist) }
}

struct IvfIndex {
    centroids: Vec<f32>,   // n_clusters * 128 f32
    lists: Vec<Vec<u32>>,  // cluster -> [vector indices]
    n_clusters: usize,
}

pub struct VectorDB {
    // All vector data and index under one lock
    data: RwLock<Vec<f32>>,   // flat [n * 128]
    ids: RwLock<Vec<u64>>,
    ivf: RwLock<Option<IvfIndex>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            ivf: RwLock::new(None),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        self.data.write().extend_from_slice(&vector);
        self.ids.write().push(id);
        *self.ivf.write() = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        // 1. Insert data (short write lock)
        {
            let mut d = self.data.write();
            let mut i = self.ids.write();
            d.reserve(count * 128);
            i.reserve(count);
            for (id, vec) in &vectors {
                d.extend_from_slice(vec);
                i.push(*id);
            }
        }

        // 2. Build IVF (takes a snapshot, computes outside lock, then stores)
        let (data_snap, n) = {
            let d = self.data.read();
            let n = d.len() / 128;
            (d.clone(), n)  // Clone the data for use in parallel build
        };

        if n >= 100 {
            let ivf = build_ivf(&data_snap, n);
            *self.ivf.write() = Some(ivf);
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        // Acquire both data and ivf read locks
        let ivf_guard = self.ivf.read();
        let data_guard = self.data.read();
        let ids_guard = self.ids.read();

        let n = ids_guard.len();
        if n == 0 { return Vec::new(); }
        let k = top_k as usize;

        if let Some(ref ivf) = *ivf_guard {
            search_ivf_fn(&data_guard, &ids_guard, ivf, vector, k)
        } else {
            search_brute_fn(&data_guard, &ids_guard, vector, k)
        }
    }
}

fn build_ivf(data: &[f32], n: usize) -> IvfIndex {
    let nc = N_CLUSTERS.min(n);
    let t0 = std::time::Instant::now();
    eprintln!("[IVF] building {} clusters for {} vecs", nc, n);

    // Init: take evenly spaced vectors
    let step = n / nc;
    let mut centroids: Vec<f32> = (0..nc)
        .flat_map(|i| data[i*step*128..(i*step+1)*128].iter().copied())
        .collect();

    let mut asgn = vec![0u32; n];

    for it in 0..KMEANS_ITERS {
        let sp = data.as_ptr() as usize;
        let cp = centroids.as_ptr() as usize;

        // Parallel assignment: each vector finds nearest centroid
        let new_asgn: Vec<u32> = (0..n).into_par_iter().map(|i| {
            let v = unsafe { std::slice::from_raw_parts((sp as *const f32).add(i*128), 128) };
            let mut bd = f32::MAX;
            let mut bc = 0u32;
            for c in 0..nc {
                let cen = unsafe { std::slice::from_raw_parts((cp as *const f32).add(c*128), 128) };
                let d = l2_distance_f32(v, cen);
                if d < bd { bd = d; bc = c as u32; }
            }
            bc
        }).collect();

        let chg = asgn.iter().zip(&new_asgn).filter(|(a,b)| a!=b).count();
        asgn = new_asgn;

        // Update centroids
        let mut sums = vec![0f32; nc * 128];
        let mut cnts = vec![0u32; nc];
        for i in 0..n {
            let c = asgn[i] as usize;
            cnts[c] += 1;
            let v = &data[i*128..(i+1)*128];
            let s = &mut sums[c*128..(c+1)*128];
            for j in 0..128 { s[j] += v[j]; }
        }
        for c in 0..nc {
            let cnt = cnts[c].max(1) as f32;
            let cs = &sums[c*128..(c+1)*128];
            let cc = &mut centroids[c*128..(c+1)*128];
            for j in 0..128 { cc[j] = cs[j] / cnt; }
        }

        eprintln!("[IVF] iter {}/{}: {} changed ({:.1}s total)", 
            it+1, KMEANS_ITERS, chg, t0.elapsed().as_secs_f64());
        if chg == 0 { break; }
    }

    let mut lists: Vec<Vec<u32>> = (0..nc).map(|_| Vec::new()).collect();
    for (i, &c) in asgn.iter().enumerate() { lists[c as usize].push(i as u32); }
    eprintln!("[IVF] done in {:.1}s, avg list {}", t0.elapsed().as_secs_f64(), n/nc);

    IvfIndex { centroids, lists, n_clusters: nc }
}

fn nearest_n(ivf: &IvfIndex, q: &[f32], k: usize) -> Vec<usize> {
    let n = ivf.n_clusters;
    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for i in 0..n {
        let c = &ivf.centroids[i*128..(i+1)*128];
        let d = l2_distance_f32(q, c);
        let e = HeapEntry { dist: OrdF32(d), id: i as u64 };
        if heap.len() < k { heap.push(e); }
        else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
    }
    let mut v: Vec<_> = heap.into_iter().map(|e| (e.dist.0, e.id as usize)).collect();
    v.sort_unstable_by(|a,b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));
    v.into_iter().map(|(_,i)| i).collect()
}

fn search_ivf_fn(data: &[f32], ids: &[u64], ivf: &IvfIndex, q: &[f32], k: usize) -> Vec<SearchResult> {
    let probes = nearest_n(ivf, q, N_PROBES);
    let mut cands: Vec<u32> = Vec::new();
    for &cid in &probes { cands.extend_from_slice(&ivf.lists[cid]); }
    let n = cands.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }

    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for &idx in &cands {
        let idx = idx as usize;
        let v = &data[idx*128..(idx+1)*128];
        let d = l2_distance_f32(q, v);
        let e = HeapEntry { dist: OrdF32(d), id: ids[idx] };
        if heap.len() < k { heap.push(e); }
        else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
    }

    let mut out: Vec<SearchResult> = heap.into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 }).collect();
    out.sort_by(|a,b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

fn search_brute_fn(data: &[f32], ids: &[u64], q: &[f32], k: usize) -> Vec<SearchResult> {
    let n = ids.len();
    let k = k.min(n);
    if k == 0 { return Vec::new(); }
    let cs = (n+3)/4;
    let res: Vec<Vec<(f32, u64)>> = (0..4).into_par_iter().map(|ci| {
        let s = ci*cs;
        let e = (s+cs).min(n);
        if s >= e { return Vec::new(); }
        let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
        for i in s..e {
            let v = &data[i*128..(i+1)*128];
            let d = l2_distance_f32(q, v);
            let en = HeapEntry { dist: OrdF32(d), id: ids[i] };
            if heap.len() < k { heap.push(en); }
            else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(en); }
        }
        heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
    }).collect();

    let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k+1);
    for ch in res {
        for (d,id) in ch {
            let e = HeapEntry { dist: OrdF32(d), id };
            if heap.len() < k { heap.push(e); }
            else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
        }
    }
    let mut out: Vec<SearchResult> = heap.into_iter()
        .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 }).collect();
    out.sort_by(|a,b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
    out
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// Pure brute-force with 4-way parallel search.
// 1M vectors * 128 dims * 4 bytes = 512MB. 
// With AVX-512 & 4 cores, throughput ~32 GB/s effective -> 512MB / 32 GB/s = 16ms/query.
// 4 threads * 1000ms / 16ms = ~62 QPS. Not great, but correct.
// We'll also try to use a simple flat structure.

#[derive(Clone, Copy, PartialEq)]
struct OrdF32(f32);
impl Eq for OrdF32 {}
impl PartialOrd for OrdF32 {
    #[inline] fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for OrdF32 {
    #[inline] fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct HeapEntry { dist: OrdF32, id: u64 }
impl PartialOrd for HeapEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
}
impl Ord for HeapEntry {
    fn cmp(&self, other: &Self) -> Ordering { self.dist.cmp(&other.dist) }
}

pub struct VectorDB {
    data: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        self.data.write().extend_from_slice(&vector);
        self.ids.write().push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut d = self.data.write();
        let mut i = self.ids.write();
        d.reserve(count * 128);
        i.reserve(count);
        for (id, vec) in vectors {
            d.extend_from_slice(&vec);
            i.push(id);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read();
        let ids = self.ids.read();
        let n = ids.len();
        if n == 0 { return Vec::new(); }
        let k = (top_k as usize).min(n);

        // Split into 4 parallel chunks
        let chunk_size = (n + 3) / 4;

        let results: Vec<Vec<(f32, u64)>> = (0..4).into_par_iter().map(|ci| {
            let start = ci * chunk_size;
            let end = (start + chunk_size).min(n);
            if start >= end { return Vec::new(); }

            let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
            for i in start..end {
                let v = &data[i * 128..(i + 1) * 128];
                let d = l2_distance_f32(vector, v);
                let e = HeapEntry { dist: OrdF32(d), id: ids[i] };
                if heap.len() < k {
                    heap.push(e);
                } else if d < heap.peek().unwrap().dist.0 {
                    heap.pop();
                    heap.push(e);
                }
            }
            heap.into_iter().map(|e| (e.dist.0, e.id)).collect()
        }).collect();

        let mut heap: BinaryHeap<HeapEntry> = BinaryHeap::with_capacity(k + 1);
        for chunk in results {
            for (d, id) in chunk {
                let e = HeapEntry { dist: OrdF32(d), id };
                if heap.len() < k { heap.push(e); }
                else if d < heap.peek().unwrap().dist.0 { heap.pop(); heap.push(e); }
            }
        }

        let mut out: Vec<SearchResult> = heap.into_iter()
            .map(|e| SearchResult { id: e.id, distance: e.dist.0 as f64 }).collect();
        out.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        out
    }
}

